UPDATE `quest_template` SET `entry`=816, `Method`=2, `ZoneOrSort`=14, `MinLevel`=8, `MaxLevel`=255, `QuestLevel`=11, `Type`=0, `RequiredClasses`=0, `RequiredRaces`=178, `RequiredSkill`=0, `RequiredSkillValue`=0, `RequiredCondition`=0, `RepObjectiveFaction`=0, `RepObjectiveValue`=0, `RequiredMinRepFaction`=0, `RequiredMinRepValue`=0, `RequiredMaxRepFaction`=0, `RequiredMaxRepValue`=0, `SuggestedPlayers`=0, `LimitTime`=0, `QuestFlags`=8, `SpecialFlags`=0, `PrevQuestId`=0, `NextQuestId`=0, `ExclusiveGroup`=0, `BreadcrumbForQuestId`=0, `NextQuestInChain`=0, `SrcItemId`=0, `SrcItemCount`=0, `SrcSpell`=0, `Title`='Lost But Not Forgotten', `Details`='$N, please, can you help me? My son Kron went hunting days ago, and he still hasn\'t returned. He went west towards the Barrens to hunt crocolisks along Southfury River. I fear the worst.$B$BAs strong as he was, his stubborn pride has always drawn him into trouble. I warned him that the crocolisks were powerful and vicious. He grew angry and stormed off.$B$BIf you can\'t find him, at least bring me a sign of his fate... even if you have to open up the stomach of every crocolisk along the Southfury\'s banks.', `Objectives`='Bring a sign of Kron\'s fate to Misha Tor\'kren at the farmstead northwest of Razor Hill.', `OfferRewardText`='Oh, my son... my beautiful son.$B$BUncertain of my son\'s fate, I have tormented myself since he left. Now that I know what\'s happened, perhaps I can finally begin to mourn.$B$BThank you, $N. Please keep this. Now that I know he is dead, I cannot bear to look at it.', `RequestItemsText`='I pray that Kron will return to me, but I\'m almost certain I know his fate already.', `EndText`='', `ObjectiveText1`='', `ObjectiveText2`='', `ObjectiveText3`='', `ObjectiveText4`='', `ReqItemId1`=4891, `ReqItemId2`=0, `ReqItemId3`=0, `ReqItemId4`=0, `ReqItemCount1`=1, `ReqItemCount2`=0, `ReqItemCount3`=0, `ReqItemCount4`=0, `ReqSourceId1`=0, `ReqSourceId2`=0, `ReqSourceId3`=0, `ReqSourceId4`=0, `ReqSourceCount1`=